};

export const App: React.FC = () => {
    const [clients, setClients] = useState<Client[]>([]);
    const [archive, setArchive] = useState<Client[]>([]);
    const [headers, setHeaders] = useState<string[]>([]);
    const [templates, setTemplates] = useState<MessageTemplate[]>([]);
    const [masters, setMasters] = useState<Master[]>([]);
    const [settings, setSettings] = useState<SettingsType>({ adminIds: '', managerIds: '', googleSheetId: '', sheetName: '', apiMode: 'GAS' });
    const [user, setUser] = useState<User | null>(() => {
        const saved = sessionStorage.getItem('user');
        return saved ? JSON.parse(saved) : { username: 'Admin', role: UserRole.Admin };
    });
    const [toasts, setToasts] = useState<ToastMessage[]>([]);
    const [savedViews, setSavedViews] = useState<SavedView[]>([]);

    const addToast = useCallback((message: string, type: 'success' | 'error' = 'success') => {
        setToasts(prev => [...prev, { id: Date.now().toString(), message, type }]);
    }, []);

    const removeToast = useCallback((id: string) => {
        setToasts(prev => prev.filter(t => t.id !== id));
    }, []);

    const refreshData = useCallback(async () => {
        try {
            const [clientData, templateData, masterData, settingsData] = await Promise.all([
                api.fetchClients(),
                api.fetchTemplates(),
                api.fetchMasters(),
                api.fetchSettings()
            ]);
            setClients(clientData.clients);
            setArchive(clientData.archive);
            setHeaders(clientData.headers);
            setTemplates(templateData);
            setMasters(masterData);
            setSettings(settingsData);
        } catch (e: any) {
            addToast(`Ошибка загрузки данных: ${e.message}`, 'error');
        }
    }, [addToast]);

    useEffect(() => {
        refreshData();
    }, [refreshData]);

    const logout = () => {
        sessionStorage.removeItem('user');
        setUser(null);
    };

    const needsSetup = !settings.googleSheetId && settings.apiMode === 'GAS';

    const handleSaveViews = (views: SavedView[]) => {
        setSavedViews(views);
        localStorage.setItem('saved_views', JSON.stringify(views));
    };

    useEffect(() => {
        const saved = localStorage.getItem('saved_views');
        if (saved) setSavedViews(JSON.parse(saved));
    }, []);

    return (
        <HashRouter>
            <ToastContainer toasts={toasts} removeToast={removeToast} />
            <Routes>
                <Route path="/tg-lk" element={<TelegramLK />} />

                <Route path="/*" element={
                    <Layout user={user} onLogout={logout} navDisabled={needsSetup}>
                        <Routes>
                            <Route path="/" element={needsSetup ? <Navigate to="/settings" replace /> : <Dashboard clients={clients} archive={archive} templates={templates} />} />
                            <Route path="/clients" element={needsSetup ? <Navigate to="/settings" replace /> : <ClientsView clients={clients} headers={headers} templates={templates} refreshData={refreshData} savedViews={savedViews} onSaveViews={handleSaveViews} />} />
                            <Route path="/clients/:id" element={needsSetup ? <Navigate to="/settings" replace /> : <ClientDetailsPage clients={clients} headers={headers} templates={templates} refreshData={refreshData} settings={settings} />} />
                            <Route path="/masters" element={needsSetup ? <Navigate to="/settings" replace /> : <MastersView masters={masters} setMasters={setMasters} clients={clients} />} />
                            <Route path="/add-client" element={needsSetup ? <Navigate to="/settings" replace /> : <AddClient settings={settings} onClientAdd={refreshData} />} />
                            <Route path="/settings" element={<Settings initialSettings={settings} initialTemplates={templates} initialMasters={masters} clients={clients} onSave={refreshData} needsSetup={needsSetup} />} />
                        </Routes>
                    </Layout>
                } />
            </Routes>
            <DevViewToggle />
        </HashRouter>
    );
};

import React, { useState, useEffect } from 'react';
import { Client, parseDate, formatDateForDisplay } from '../types';
import NewUserForm from './NewUserForm';

const TelegramLK: React.FC = () => {
    const [client, setClient] = useState<Client | null>(null);
    const [loading, setLoading] = useState(true);
    const [chatId, setChatId] = useState<string>('');

    useEffect(() => {
        const tg = (window as any).Telegram?.WebApp;
        if (tg) {
            tg.expand();
            tg.ready();

            const userChatId = String(tg.initDataUnsafe?.user?.id || '');
            setChatId(userChatId);

            if (userChatId) {
                checkUserStatus(userChatId);
            } else {
                // Для тестов в браузере
                setLoading(false);
            }
        }
    }, []);

    const checkUserStatus = async (id: string) => {
        try {
            const response = await fetch('/api/crm', {
                method: 'POST',
                body: JSON.stringify({ action: 'get_client_by_chatid', chatId: id })
            });
            const result = await response.json();
            if (result.status === 'success' && result.client) {
                setClient(result.client);
            }
        } catch (e) {
            console.error("Auth check failed", e);
        } finally {
            setLoading(false);
        }
    };

    const handleLeadSubmit = async (phone: string) => {
        const tg = (window as any).Telegram?.WebApp;
        const userData = tg?.initDataUnsafe?.user || {};

        await fetch('/api/crm', {
            method: 'POST',
            body: JSON.stringify({ 
                action: 'submit_lead', 
                chatId,
                phone,
                name: `${userData.first_name || ''} ${userData.last_name || ''}`.trim() || 'Новый лид',
                username: userData.username
            })
        });
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center h-screen bg-[#f1f1f7] dark:bg-gray-950">
                <div className="w-10 h-10 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
            </div>
        );
    }

    // Если клиент не найден - показываем форму для новых пользователей
    if (!client) {
        return <NewUserForm chatId={chatId} onSubmit={handleLeadSubmit} />;
    }

    // Личный кабинет клиента
    return (
        <div className="min-h-screen bg-[#f1f1f7] dark:bg-gray-950 font-sans pb-10">
            {/* Header */}
            <div className="bg-white dark:bg-gray-900 px-6 pt-10 pb-8 rounded-b-[40px] shadow-sm">
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <h1 className="text-2xl font-black text-gray-900 dark:text-white leading-tight">
                            Привет, <span className="text-blue-600">{client['Имя клиента'].split(' ')[1] || 'Гость'}</span>!
                        </h1>
                        <p className="text-gray-400 text-sm font-medium mt-1">Твои колеса в безопасности</p>
                    </div>
                    <div className="bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 p-3 rounded-2xl">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" /></svg>
                    </div>
                </div>

                <div className="bg-gradient-to-br from-blue-600 to-indigo-700 rounded-[30px] p-6 text-white shadow-xl shadow-blue-500/20">
                    <div className="flex justify-between items-center mb-4">
                        <span className="text-blue-100 text-[10px] font-bold uppercase tracking-widest">Статус договора</span>
                        <span className="bg-white/20 px-3 py-1 rounded-full text-[9px] font-bold uppercase">{client['Статус сделки']}</span>
                    </div>
                    <div className="text-3xl font-black mb-1">На складе</div>
                    <div className="text-blue-100 text-sm opacity-80">Договор №{client['Договор']}</div>

                    <div className="mt-6 pt-6 border-t border-white/10 flex justify-between items-end">
                        <div>
                            <div className="text-[10px] text-blue-200 uppercase font-bold mb-1">Срок до</div>
                            <div className="text-xl font-black">{formatDateForDisplay(client['Окончание'])}</div>
                        </div>
                        <button className="bg-white text-blue-700 px-4 py-2 rounded-xl text-xs font-bold active:scale-95 transition-transform">
