import { Pool } from 'pg';

// Cache the database pool for reuse across function invocations in Vercel environment
let cachedPool: Pool | null = null;

/**
 * Initializes and returns a PostgreSQL connection pool.
 */
function getDbPool() {
    if (cachedPool) return cachedPool;
    const connectionString = process.env.POSTGRES_URL || process.env.STOREGE_POSTGRES_URL;
    if (!connectionString) throw new Error("POSTGRES_URL is not defined");

    cachedPool = new Pool({
        connectionString,
        ssl: { rejectUnauthorized: false },
        max: 10,
        connectionTimeoutMillis: 10000,
    });
    return cachedPool;
}

/**
 * Helper to send messages via Telegram Bot API.
 */
async function crmSendMessage(chatId: string, message: string) {
    const token = process.env.TELEGRAM_BOT_TOKEN;
    if (!token) return;
    const url = `https://api.telegram.org/bot${token}/sendMessage`;
    try {
        await fetch(url, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                chat_id: String(chatId),
                text: message,
                parse_mode: 'HTML'
            })
        });
    } catch (e) {
        console.error("Telegram Send Error:", e);
    }
}

/**
 * Helper to log history events into the Postgres database.
 */
async function logHistory(pool: Pool, clientId: string, user: string, action: string, details: string) {
    try {
        await pool.query(
            'INSERT INTO history (client_id, user_name, action, details) VALUES ($1, $2, $3, $4)',
            [clientId, user, action, details]
        );
    } catch (e) {
        console.error("History Logging Error:", e);
    }
}

/**
 * Main Vercel Serverless Function handler for CRM API requests.
 */
export default async function handler(req: any, res: any) {
    // Only allow POST requests for this endpoint
    if (req.method !== 'POST') return res.status(405).end();

    // Fix: Define body, action, user, pool, and result variables in the handler scope to resolve 1-based line errors
    const body = req.body;
    const action = body.action;
    const user = body.user || 'System';
    const pool = getDbPool();
    let result: any = { status: 'error', message: 'Unknown action: ' + action };

    try {
        switch (action) {
            case 'testconnection':
                result = { status: 'success', message: 'Vercel Postgres Connection OK' };
                break;

            case 'get_client_by_chatid':
                // Fix: Find client data by Chat ID using pg pool as used in line 19
                const gcRes2 = await pool.query(`
                    SELECT data FROM clients 
                    WHERE (data->>'Chat ID' = $1 OR data->>'Chat ID' = $2)
                    AND is_archived = FALSE 
                    LIMIT 1
                `, [body.chatId, String(body.chatId)]);
                result = { status: 'success', client: gcRes2.rows[0]?.data };
                break;

            case 'lk_pickup':
                // Fix: Handle pickup request using provided snippet logic and defined helper functions
                const pickupMsg = `🚗 <b>ЗАЯВКА НА ВЫДАЧУ (ЛК)</b>\n\n👤 <b>Клиент:</b> ${body.name}\n📄 <b>Договор:</b> <code>${body.contract}</code>\n🆔 <b>ChatID:</b> <code>${body.chatId}</code>`;
                await crmSendMessage(process.env.ADMIN_CHAT_ID || body.chatId, pickupMsg);
                await logHistory(pool, body.contract || 'LK', user, 'Заявка на выдачу', 'Через Mini App');
                result = { status: 'success' };
                break;

            case 'lk_extend':
                // Fix: Handle extension request using provided snippet logic and defined helper functions
                const extendMsg = `📅 <b>ЗАЯВКА НА ПРОДЛЕНИЕ (ЛК)</b>\n\n👤 <b>Клиент:</b> ${body.name}\n📄 <b>Договор:</b> <code>${body.contract}</code>\n🆔 <b>ChatID:</b> <code>${body.chatId}</code>`;
                await crmSendMessage(process.env.ADMIN_CHAT_ID || body.chatId, extendMsg);
                await logHistory(pool, body.contract || 'LK', user, 'Заявка на продление', 'Через Mini App');
                result = { status: 'success' };
                break;

            case 'getclients':
                // Implementation for fetching clients and archive for the Vercel backend
                const clientsRes = await pool.query('SELECT data FROM clients WHERE is_archived = FALSE');
                const archiveRes = await pool.query('SELECT data FROM clients WHERE is_archived = TRUE');
                result = { 
                    status: 'success', 
                    clients: clientsRes.rows.map(r => r.data),
                    archive: archiveRes.rows.map(r => r.data)
                };
                break;

            case 'getmasters':
                const mastersRes = await pool.query('SELECT data FROM masters');
                result = { status: 'success', masters: mastersRes.rows.map(r => r.data) };
                break;

            case 'gettemplates':
                const templatesRes = await pool.query('SELECT data FROM templates');
                result = { status: 'success', templates: templatesRes.rows.map(r => r.data) };
                break;
        }

        return res.status(200).json(result);
    } catch (error: any) {
        console.error("CRM Handler Error:", error);
        return res.status(500).json({ status: 'error', message: error.message });
    }
}

import { Pool } from 'pg';

let cachedPool: Pool | null = null;

function getDbPool() {
    if (cachedPool) return cachedPool;
    const connectionString = process.env.POSTGRES_URL || process.env.STOREGE_POSTGRES_URL;
    if (!connectionString) throw new Error("POSTGRES_URL is not defined");

    cachedPool = new Pool({
        connectionString,
        ssl: { rejectUnauthorized: false },
        max: 10,
        connectionTimeoutMillis: 10000,
    });
    return cachedPool;
}

const BOT_TOKEN = process.env.TELEGRAM_BOT_TOKEN;
const ADMIN_CHAT_ID = process.env.ADMIN_CHAT_ID;

export default async function handler(req: any, res: any) {
    if (req.method !== 'POST') return res.status(405).end();
    if (!BOT_TOKEN) return res.status(500).json({ error: "Token not set" });

    try {
        const pool = getDbPool();
        const update = req.body;

        if (update.message) {
            await handleMessage(pool, update.message);
        } else if (update.callback_query) {
            await handleCallback(pool, update.callback_query);
        }

        return res.status(200).send('OK');
    } catch (error: any) {
        console.error('[BOT ERROR]', error);
        return res.status(200).send('OK');
    }
}

async function handleMessage(pool: Pool, msg: any) {
    const chatId = String(msg.chat.id);
    const text = msg.text?.trim();

    if (msg.contact) {
        return handleContactAuth(pool, chatId, msg.contact);
    }

    if (!text) return;

    // Обработка /start с параметрами (рефералы)
    if (text.toLowerCase().startsWith('/start')) {
        const parts = text.split(' ');
        const startParam = parts.length > 1 ? parts[1] : null;

        await setSession(pool, chatId, null, { ref: startParam });

        if (startParam && startParam.startsWith('ref_')) {
            const referrerId = startParam.replace('ref_', '');
            if (referrerId !== chatId && ADMIN_CHAT_ID) {
                await sendTelegram('sendMessage', {
                    chat_id: ADMIN_CHAT_ID,
                    text: `📢 <b>Новый реферал!</b>\n\nПользователь <code>${chatId}</code> пришел по ссылке от <code>${referrerId}</code>.`,
                    parse_mode: 'HTML'
                });
            }
        }

        return sendTelegram('sendMessage', {
            chat_id: chatId,
            text: "👋 <b>Добро пожаловать в Отель Шин!</b>\n\nЯ ваш персональный помощник по хранению колес. Выберите действие:",
            parse_mode: 'HTML',
            reply_markup: getMainMenu()
        });
    }

    const session = await getSession(pool, chatId);

    if (session.state?.startsWith('signup_')) {
        return handleSignupFlow(pool, chatId, text, session);
    }

    if (session.state === 'lk_pickup_date') {
        return handlePickupRequest(pool, chatId, text);
    }

    if (msg.chat.type === 'private') {
        await sendTelegram('sendMessage', {
            chat_id: chatId,
            text: "Используйте меню или нажмите /start.",
            reply_markup: { inline_keyboard: [[{ text: "🏠 Главное меню", callback_data: "main_menu" }]] }
        });
    }
}

async function handleCallback(pool: Pool, cb: any) {
    const chatId = String(cb.message.chat.id);
    const messageId = cb.message.message_id;
    const data = cb.data;
    const session = await getSession(pool, chatId);

    let text = "";
    let keyboard: any = null;

    switch (data) {
        case 'main_menu':
            await setSession(pool, chatId, null, {});
            text = "🏠 <b>Главное меню:</b>";
            keyboard = getMainMenu();
            break;

        case 'flow_lk':
            const client = await findClientByChatId(pool, chatId);
            if (client) {
                text = `👤 <b>Личный кабинет</b>\n\n<b>Клиент:</b> ${client['Имя клиента']}\n<b>Договор:</b> <code>${client['Договор']}</code>\n<b>Срок до:</b> ${formatDate(client['Окончание'])}`;
                keyboard = getLkMenu(client);
            } else {
                text = `❌ <b>Вы не авторизованы</b>\n\nДля доступа к Личному кабинету нужно привязать номер телефона.`;
                return sendTelegram('sendMessage', {
                    chat_id: chatId,
                    text: text,
                    parse_mode: 'HTML',
                    reply_markup: { 
                        keyboard: [[{ text: "📱 Привязать телефон", request_contact: true }]],
                        resize_keyboard: true, one_time_keyboard: true
                    }
                });
            }
            break;

        case 'info_prices':
            text = "💰 <b>Наши цены:</b>\n\n• R13-R15: 500 ₽/мес\n• R16-R19: 600 ₽/мес\n• R20+: 700 ₽/мес\n\n<i>Мойка и упаковка уже включены в первый месяц!</i>";
            keyboard = { inline_keyboard: [[{ text: "⬅️ Назад", callback_data: "main_menu" }]] };
            break;

        case 'flow_signup':
            await setSession(pool, chatId, 'signup_phone', {});
            text = "✍️ <b>Запись на хранение</b>\n\nШаг 1/3. Введите ваш номер телефона:";
            keyboard = { inline_keyboard: [[{ text: "❌ Отмена", callback_data: "main_menu" }]] };
            break;

        case 'lk_referral':
            text = "🎁 <b>Реферальная программа</b>\n\nПриведи друга — получи <b>1 месяц в подарок</b>!\n\nВаша ссылка:\n<code>https://t.me/OtelShinBot?start=ref_${chatId}</code>";
            keyboard = { inline_keyboard: [[{ text: "⬅️ Назад", callback_data: "flow_lk" }]] };
            break;

        case 'lk_pickup':
            await setSession(pool, chatId, 'lk_pickup_date', {});
            text = "🚗 <b>Забрать шины</b>\n\nНапишите желаемую дату и время выдачи (например: Завтра в 14:00):";
            keyboard = { inline_keyboard: [[{ text: "❌ Отмена", callback_data: "flow_lk" }]] };
            break;

        case 'lk_extend':
            const extClient = await findClientByChatId(pool, chatId);
            if (!extClient) return;
            const extState = { months: 1, hasRims: false };
            await setSession(pool, chatId, 'ext_process', extState);
            text = `📅 <b>Продление хранения</b>\n\nТекущий тариф: ${extClient['Цена за месяц']} ₽/мес.\nВыберите срок:`;
            keyboard = getExtensionMenu(1, false);
            break;

        case 'ext_toggle_rims':
            const currentExt = session.data || { months: 1, hasRims: false };
            currentExt.hasRims = !currentExt.hasRims;
            await setSession(pool, chatId, 'ext_process', currentExt);
            text = `📅 <b>Продление хранения</b>\n\nНастройка опций:`;
            keyboard = getExtensionMenu(currentExt.months, currentExt.hasRims);
            break;

        case 'ext_calc':
            const c = await findClientByChatId(pool, chatId);
            if (!c) return;
            const s = session.data || { months: 1, hasRims: false };
            const base = parseInt(c['Цена за месяц']) || 500;
            const rimExtra = s.hasRims ? 100 : 0;
            const total = (base + rimExtra) * s.months;
            text = `💵 <b>Расчет продления</b>\n\nСрок: ${s.months} мес.\nДиски: ${s.hasRims ? 'Да' : 'Нет'}\n\n<b>Итого: ${total} ₽</b>\n\nЗаявка отправлена менеджеру, он свяжется для оплаты.`;
            if (ADMIN_CHAT_ID) {
                await sendTelegram('sendMessage', {
                    chat_id: ADMIN_CHAT_ID,
                    text: `💰 <b>ЗАЯВКА НА ПРОДЛЕНИЕ</b>\n\n👤 ${c['Имя клиента']}\n📄 Договор: ${c['Договор']}\n🗓 Срок: ${s.months} мес.\n💳 Сумма: ${total} ₽`,
                    parse_mode: 'HTML'
                });
            }
            keyboard = { inline_keyboard: [[{ text: "🏠 В меню", callback_data: "main_menu" }]] };
            break;
    }

    if (data.startsWith('ext_set_m_')) {
        const m = parseInt(data.split('_')[3]);
        const cur = session.data || { months: 1, hasRims: false };
        cur.months = m;
        await setSession(pool, chatId, 'ext_process', cur);
        text = `📅 <b>Продление хранения</b>\n\nВыбрано: ${m} мес.`;
        keyboard = getExtensionMenu(m, cur.hasRims);
    }

    if (text) {
        await sendTelegram('editMessageText', {
            chat_id: chatId, message_id: messageId,
            text, parse_mode: 'HTML', reply_markup: keyboard
        });
    }
    await sendTelegram('answerCallbackQuery', { callback_query_id: cb.id });
}

async function handleContactAuth(pool: Pool, chatId: string, contact: any) {
    let phone = contact.phone_number;
    if (!phone.startsWith('+')) phone = '+' + phone;

    const res = await pool.query(
        `SELECT id, data FROM clients WHERE phone = $1 OR data->>'Телефон' = $1 LIMIT 1`,
        [phone]
    );

    if (res.rows.length > 0) {
        const client = res.rows[0].data;
        const clientId = res.rows[0].id;
        client['Chat ID'] = chatId;
        await pool.query(`UPDATE clients SET data = $1 WHERE id = $2`, [JSON.stringify(client), clientId]);
        await sendTelegram('sendMessage', {
            chat_id: chatId, text: "✅ <b>Успешно!</b>\n\nТеперь вам доступен Личный кабинет.", parse_mode: 'HTML',
            reply_markup: { remove_keyboard: true }
        });
        const text = `👤 <b>Личный кабинет</b>\n\n<b>Клиент:</b> ${client['Имя клиента']}\n<b>Договор:</b> <code>${client['Договор']}</code>`;
        return sendTelegram('sendMessage', { chat_id: chatId, text, parse_mode: 'HTML', reply_markup: getLkMenu(client) });
    } else {
        return sendTelegram('sendMessage', {
            chat_id: chatId, text: `❌ Номер <b>${phone}</b> не найден.\n\nОбратитесь к менеджеру: @OtelShinAdmin`,
            parse_mode: 'HTML', reply_markup: { remove_keyboard: true }
        });
    }
}

async function handleSignupFlow(pool: Pool, chatId: string, text: string, session: any) {
    if (session.state === 'signup_phone') {
        await setSession(pool, chatId, 'signup_car', { phone: text });
        return sendTelegram('sendMessage', { chat_id: chatId, text: "✅ Принято.\n\nШаг 2/3. Номер авто:" });
    }
    if (session.state === 'signup_car') {
        await setSession(pool, chatId, 'signup_district', { ...session.data, car: text });
        return sendTelegram('sendMessage', { chat_id: chatId, text: "✅ Принято.\n\nШаг 3/3. Ваш адрес для забора:" });
    }
    if (session.state === 'signup_district') {
        const report = `🔥 <b>ЗАЯВКА</b>\n\n👤 <b>ID:</b> ${chatId}\n📞 <b>Тел:</b> ${session.data.phone}\n🚗 <b>Авто:</b> ${session.data.car}\n📍 <b>Адрес:</b> ${text}`;
        if (ADMIN_CHAT_ID) await sendTelegram('sendMessage', { chat_id: ADMIN_CHAT_ID, text: report, parse_mode: 'HTML' });
        await setSession(pool, chatId, null, {});
        return sendTelegram('sendMessage', { chat_id: chatId, text: "✅ <b>Заявка принята!</b>", reply_markup: getMainMenu() });
    }
}

async function handlePickupRequest(pool: Pool, chatId: string, text: string) {
    const client = await findClientByChatId(pool, chatId);
    const report = `🚗 <b>ЗАЯВКА НА ВЫДАЧУ</b>\n\n👤 ${client ? client['Имя клиента'] : chatId}\n📅 <b>Когда:</b> ${text}`;
    if (ADMIN_CHAT_ID) await sendTelegram('sendMessage', { chat_id: ADMIN_CHAT_ID, text: report, parse_mode: 'HTML' });
    await setSession(pool, chatId, null, {});
    return sendTelegram('sendMessage', { chat_id: chatId, text: "✅ Заявка на выдачу принята!", reply_markup: getMainMenu() });
}

async function getSession(pool: Pool, chatId: string) {
    const res = await pool.query('SELECT state, data FROM bot_sessions WHERE chat_id = $1', [chatId]);
    return res.rows[0] || { state: null, data: {} };
}

async function setSession(pool: Pool, chatId: string, state: string | null, data: any) {
    await pool.query(`INSERT INTO bot_sessions (chat_id, state, data, updated_at) VALUES ($1, $2, $3, NOW()) ON CONFLICT (chat_id) DO UPDATE SET state = EXCLUDED.state, data = EXCLUDED.data, updated_at = NOW()`, [chatId, state, JSON.stringify(data)]);
}

async function findClientByChatId(pool: Pool, chatId: string) {
    const res = await pool.query(`SELECT data FROM clients WHERE (data->>'Chat ID' = $1 OR data->>'Chat ID' = $2) AND is_archived = FALSE LIMIT 1`, [chatId, chatId]);
    return res.rows[0]?.data;
}

